public boolean apply(Node n) {
  // When the node is null it means we reached the implicit return
  // where the function returns (possibly without a return statement)
  if (n == null) {
    return false;
  }

  // Check if the node is a function call and has side effects
  if (n.isCall() && NodeUtil.functionCallHasSideEffects(n)) {
    return true;
  }

  // Check if the node is a constructor call and has side effects
  if (n.isNew() && NodeUtil.constructorCallHasSideEffects(n)) {
    return true;
  }

  // Traverse the children of the current node
  for (Node c = n.getFirstChild(); c != null; c = c.getNext()) {
    // Recursively apply the function on the child nodes
    // and check if any child satisfies the condition
    if (!ControlFlowGraph.isEnteringNewCfgNode(c) && apply(c)) {
      return true;
    }
  }

  // If no conditions matched, return false
  return false;
}
```

